package main

import (
	"log"
	"net"

	"google.golang.org/grpc"
	"google.golang.org/grpc/reflection"

	pbUser "path/to/user/service/proto"
	pbOrder "path/to/order/service/proto"
	pbPayment "path/to/payment/service/proto"

	userService "path/to/user/service/server"
	orderService "path/to/order/service/server"
	paymentService "path/to/payment/service/server"
)

func main() {
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("failed to listen: %v", err)
	}

	grpcServer := grpc.NewServer()

	// Register user service
	pbUser.RegisterUserServiceServer(grpcServer, &userService.Server{})

	// Register order service
	pbOrder.RegisterOrderServiceServer(grpcServer, &orderService.Server{})

	// Register payment service
	pbPayment.RegisterPaymentServiceServer(grpcServer, &paymentService.Server{})

	// Enable reflection for service discovery
	reflection.Register(grpcServer)

	log.Println("Starting gRPC server...")
	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}